<?php $isClient = \App\Core\Auth::user()['role'] === 'client'; ?>
<div class="page-header"><div><h2><?= $isClient ? 'Help Center' : 'Knowledge Base' ?></h2><p><?= $isClient ? 'Browse published client-facing help articles and operating guidance.' : 'Keep reusable answers, operating procedures, and client-ready help articles inside the CRM.' ?></p></div></div>
<div class="grid grid-3"><?php foreach (($categories ?? []) as $category): ?><div class="card"><div class="kpi-label"><?= e($category['category_name']) ?></div><div class="kpi-value"><?= e((string)$category['total']) ?></div></div><?php endforeach; ?></div>
<div class="card"><form method="get" class="stack-form"><input type="hidden" name="page" value="knowledge_base"><div class="grid grid-2"><?php if (!$isClient): ?><select name="visibility"><option value="">All visibility</option><?php foreach (['internal','client'] as $scope): ?><option value="<?= e($scope) ?>" <?= (($filters['visibility'] ?? '') === $scope) ? 'selected' : '' ?>><?= e(ucfirst($scope)) ?></option><?php endforeach; ?></select><?php endif; ?><input type="text" name="q" placeholder="Search articles" value="<?= e($filters['q'] ?? '') ?>"></div><button type="submit">Apply Filters</button></form></div>
<?php if (!$isClient && \App\Core\Auth::can('knowledge_base','create')): ?>
<div class="card"><h3>Create Article</h3><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="create"><div class="grid grid-3"><input type="text" name="title" placeholder="Article title" required><input type="text" name="category_name" placeholder="Category" value="Operations"><select name="visibility_scope"><?php foreach (['internal' => 'Internal', 'client' => 'Client'] as $value => $label): ?><option value="<?= e($value) ?>"><?= e($label) ?></option><?php endforeach; ?></select></div><textarea name="body_text" placeholder="Write the article body or SOP" rows="6"></textarea><label><input type="checkbox" name="is_published" value="1" checked> Published</label><button type="submit">Create Article</button></form></div>
<?php endif; ?>
<div class="card"><table><thead><tr><th>Title</th><th>Category</th><?php if (!$isClient): ?><th>Visibility</th><th>Status</th><?php endif; ?><th>Updated</th><th><?= $isClient ? 'Article' : 'Actions' ?></th></tr></thead><tbody><?php foreach ($articles as $article): ?><tr><td><?= e($article['title']) ?><div class="meta"><?= e(mb_strimwidth((string)$article['body_text'], 0, 140, '…')) ?></div></td><td><?= e($article['category_name']) ?></td><?php if (!$isClient): ?><td><?= e(ucfirst($article['visibility_scope'])) ?></td><td><?= !empty($article['is_published']) ? 'Published' : 'Draft' ?></td><?php endif; ?><td><?= e($article['updated_at']) ?></td><td><?php if ($isClient): ?><div style="white-space:pre-wrap"><?= e($article['body_text']) ?></div><?php else: ?><?php if (\App\Core\Auth::can('knowledge_base','edit')): ?><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="update"><input type="hidden" name="id" value="<?= e((string)$article['id']) ?>"><input type="text" name="title" value="<?= e($article['title']) ?>"><div class="grid grid-3"><input type="text" name="category_name" value="<?= e($article['category_name']) ?>"><select name="visibility_scope"><?php foreach (['internal' => 'Internal', 'client' => 'Client'] as $value => $label): ?><option value="<?= e($value) ?>" <?= $article['visibility_scope'] === $value ? 'selected' : '' ?>><?= e($label) ?></option><?php endforeach; ?></select><label><input type="checkbox" name="is_published" value="1" <?= !empty($article['is_published']) ? 'checked' : '' ?>> Published</label></div><textarea name="body_text" rows="4"><?= e($article['body_text']) ?></textarea><button type="submit">Save</button></form><?php endif; ?><?php if (\App\Core\Auth::can('knowledge_base','delete')): ?><form method="post" onsubmit="return confirm('Delete this article?')"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$article['id']) ?>"><button type="submit">Delete</button></form><?php endif; ?><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
